// Minimal auto-render stub that integrates with the katex stub above.
window.renderMathInElement = window.renderMathInElement || function(root, options){
    options = options || {};
    const delimiters = options.delimiters || [ {left:'$$', right:'$$', display:true}, {left:'$', right:'$', display:false} ];
    const re = /\$\$([\s\S]+?)\$\$|\$([^\$\n][^\$]*)\$/g;
    const toReplace = [];
    
    // First pass: collect all nodes to replace (avoid mutation during walk)
    const walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT, null, false);
    let node;
    while(node = walker.nextNode()){
        if(!node || !node.nodeValue || !node.nodeValue.trim()) continue;
        const text = node.nodeValue;
        re.lastIndex = 0;
        if(re.test(text)){
            toReplace.push(node);
        }
    }
    
    // Second pass: process collected nodes (mutations won't affect walker)
    toReplace.forEach(function(node){
        const text = node.nodeValue;
        const parent = node.parentNode;
        const wrapper = document.createDocumentFragment();
        let match;
        let lastIndex = 0;
        re.lastIndex = 0;
        let found = false;
        while((match = re.exec(text)) !== null){
            found = true;
            const pre = text.slice(lastIndex, match.index);
            if(pre) wrapper.appendChild(document.createTextNode(pre));
            const expr = match[1] || match[2];
            const span = document.createElement('span');
            span.className = 'katex';
            try{
                window.katex.render(expr, span, {displayMode: Boolean(match[1])});
            }catch(e){
                span.textContent = expr;
            }
            wrapper.appendChild(span);
            lastIndex = re.lastIndex;
        }
        if(found){
            const post = text.slice(lastIndex);
            if(post) wrapper.appendChild(document.createTextNode(post));
            parent.replaceChild(wrapper, node);
        }
    });
};
